class Solution:
    def max_stapled_pages(self, pages, staples):
        n = len(pages)
        pages.sort()
        dp = [0] * (staples + 1)
        for i in range(1, staples + 1):
            for j in range(n):
                if pages[j] <= i:
                    dp[i] = max(dp[i], dp[i - 1] + pages[j])
        return dp[staples]


