#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    int max_stapled_pages(vector<int>& pages, int staples) {
        sort(pages.begin(), pages.end());
        vector<int> dp(staples + 1, 0);
        for (int i = 1; i <= staples; ++i) {
            for (int j = 0; j < pages.size(); ++j) {
                if (pages[j] <= i) {
                    dp[i] = max(dp[i], dp[i - 1] + pages[j]);
                }
            }
        }
        return dp[staples];
    }
};
int main() {
    int n;
    cin >> n;
    vector<int> pages(n);
    for (int i = 0; i < n; ++i) {
        cin >> pages[i];
    }
    int staples;
    cin >> staples;
    Solution s;
    cout << s.max_stapled_pages(pages, staples) << endl;
    return 0;
}
